   107→  if (!result.empty()) {
   108→    if (result.size() > 1 || !Utility::isValidRefererValue(result[0]->value().getStringView())) {
   109→      // A request header shouldn't have multiple referer field.
   110→      request_headers.remove(Http::CustomHeaders::get().Referer);
