   114→  // If we are "using remote address" this means that we create/append to XFF with our immediate
   115→  // peer. Cases where we don't "use remote address" include trusted double proxy where we expect
   116→  // our peer to have already properly set XFF, etc.
   117→  Network::Address::InstanceConstSharedPtr final_remote_address;
   118→  bool allow_trusted_address_checks = false;
   119→  const uint32_t xff_num_trusted_hops = config.xffNumTrustedHops();
   120→
   121→  if (config.useRemoteAddress()) {
   122→    allow_trusted_address_checks = request_headers.ForwardedFor() == nullptr;
   123→    // If there are any trusted proxies in front of this Envoy instance (as indicated by
   124→    // the xff_num_trusted_hops configuration option), get the trusted client address
   125→    // from the XFF before we append to XFF.
   126→    if (xff_num_trusted_hops > 0) {
   127→      final_remote_address =
   128→          Utility::getLastAddressFromXFF(request_headers, xff_num_trusted_hops - 1).address_;
   129→    }
   130→    // If there aren't any trusted proxies in front of this Envoy instance, or there
   131→    // are but they didn't populate XFF properly, the trusted client address is the
   132→    // source address of the immediate downstream's connection to us.
   133→    if (final_remote_address == nullptr) {
   134→      final_remote_address = connection.connectionInfoProvider().remoteAddress();
   135→    }
   136→    if (!config.skipXffAppend()) {
   137→      if (Network::Utility::isLoopbackAddress(
   138→              *connection.connectionInfoProvider().remoteAddress())) {
   139→        Utility::appendXff(request_headers, config.localAddress());
   140→      } else {
   141→        Utility::appendXff(request_headers, *connection.connectionInfoProvider().remoteAddress());
   142→      }
   143→    }
   144→    // If the prior hop is not a trusted proxy, overwrite any
   145→    // x-forwarded-proto/x-forwarded-port value it set as untrusted. Alternately if no
   146→    // x-forwarded-proto/x-forwarded-port header exists, add one if configured.
   147→    if (xff_num_trusted_hops == 0 || request_headers.ForwardedProto() == nullptr) {
   148→      request_headers.setReferenceForwardedProto(
   149→          connection.ssl() ? Headers::get().SchemeValues.Https : Headers::get().SchemeValues.Http);
   150→    }
   151→    if (config.appendXForwardedPort() &&
   152→        (xff_num_trusted_hops == 0 || request_headers.ForwardedPort() == nullptr)) {
   153→      const Envoy::Network::Address::Ip* ip =
   154→          connection.streamInfo().downstreamAddressProvider().localAddress()->ip();
   155→      if (ip) {
