   165→    // used for determining internal/external status (see below).
   166→    OriginalIPDetectionParams params = {request_headers,
   167→                                        connection.connectionInfoProvider().remoteAddress()};
   168→    for (const auto& detection_extension : config.originalIpDetectionExtensions()) {
   169→      const auto result = detection_extension->detect(params);
   170→
   171→      if (result.reject_options.has_value()) {
   172→        return {nullptr, result.reject_options};
   173→      }
   174→
   175→      if (result.detected_remote_address) {
